var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......으음.","JPN":"……う～ん。","ENG":"Erm...","TWN":"……嗚。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 정신이 드세요 경정님?","JPN":"警視様、気がつきましたか？","ENG":"Ah, you're awake, Major.","TWN":"啊，妳清醒了嗎，警正大人？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"난...... 이게 어떻게 된 거지?","JPN":"私は……いったい何があったの？","ENG":"What... What happened?","TWN":"我……怎麼了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"휴, 상처가 심해서 걱정했는데 정신이 드셔서 다행이에요.","JPN":"ふう、怪我がひどくて心配したんですが、目が覚めてよかったです。","ENG":"Phew, you were seriously injured. I'm glad you came to.","TWN":"呼，我還擔心妳傷得很嚴重呢，妳清醒過來真是太好了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......경위? 당신이 그것들을 다 해치운 거야?","JPN":"……マエカワ警部補？　あなたがあいつらを一掃したの？","ENG":"Lieutenant? Did you take them all down?","TWN":"……警衛？那些人都是妳解決的嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하, 그럴 리가요. 저 같은 무능력자가 무슨 수로요.","JPN":"あはは、まさか。\\n私のような無能力者にそんなことできるわけないでしょう？","ENG":"Ah hah hah, I wish I did. How could an incompetent like myself do something so amazing?","TWN":"啊哈哈，怎麼可能，像我這種無能力者怎麼做得到。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그러면 어떻게......?","JPN":"じゃあ、どうやって……","ENG":"Then what happened?","TWN":"那是怎麼……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무래도 마젤란 예언회가 그 여학생을 노리고 있는 것 같아서 말이죠.","JPN":"どうもマジェラン預言会があの女子生徒を狙っているような気がしたので。","ENG":"I figured the Magellan's Prediction Society was coming after that student.","TWN":"麥哲倫預言會的目標似乎是那個女學生呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님을 쫓아오면서 블랙타이드에 협조 요청을 했어요.","JPN":"警視様を追いかけながら、ブラックタイドに協力を要請しました。","ENG":"So I called the Black Tide on the way to you.","TWN":"我在追警正大人的時候，一邊向黑潮發出了協助請求。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"블랙타이드라면...... 유명한 용병 회사잖아?","JPN":"ブラックタイドって……あの有名な傭兵会社？","ENG":"The Black Tide? Isn't that a famous mercenary company?","TWN":"黑潮……不是那個有名的傭兵公司嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런 곳을 어떻게......?","JPN":"そんな所にどうやって……","ENG":"I didn't know you had connections in these kind of businesses.","TWN":"妳怎麼知道那種地方……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"블랙타이드에는 전직 경찰특공대 출신 분들이 많으시거든요.","JPN":"ブラックタイドには、元警察特攻隊の方々が多くいらっしゃいます。","ENG":"There are a lot of former SWAT members working in the Black Tide.","TWN":"黑潮裡有很多人是原警察特攻隊出身的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 저희 요청엔 보수와 상관없이 도움을 주고 계세요.","JPN":"なので私たちが要請すれば、報酬に関わらず力を貸してくださるんです。","ENG":"They help us at our request, regardless of the pay.","TWN":"所以對於我們的請求，無論報酬如何，他們都會予以協助。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 무료 봉사기관은 아닌지라 기름값 정도는 제가 따로 대드려야 했지만......","JPN":"まあ、ボランティア団体ではないので、\\nガソリン代くらいは私がお渡ししたんですが……","ENG":"They don't exactly work for free, so I had to pay for gas, but...","TWN":"不過，畢竟他們不是慈善機構，所以油錢還是得分別給一下……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무튼 정말 위험했어요. 아슬아슬했다니까요?","JPN":"とにかく、本当に危なかったです。ギリギリでしたから！","ENG":"It was dangerous, you know. It was very, very close.","TWN":"總之，真是危險啊。差點就出事了呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 그리고 이거......","JPN":"ああ、それからこれ……","ENG":"Oh, right. I believe this is yours.","TWN":"啊，這個……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그거! 이리 줘!","JPN":"そ、それ！　返して！","ENG":"Th-that! Give it to me!","TWN":"那、那個！把那個給我！"},"stage":{"bg":"POLICE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님 머리핀이죠? 현장에 떨어져있더라고요.","JPN":"警視様のヘアピンですよね？　現場に落ちてたんです。","ENG":"This is your hair pin, right? I found it lying on the ground at the scene.","TWN":"這是警正大人的髮夾吧？它掉在現場了。"},"stage":{"bg":"POLICE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"직접 달아드리려니 그림이 좀 이상해서, 하하......","JPN":"付けてあげようとしたんですけど、なんだか上手くできなくて。\\nはは……","ENG":"I could have put this on you myself, but I felt awkward doing it. Hah hah.","TWN":"本來想直接幫妳戴上的，但總覺得那樣有點奇怪，哈哈……"},"stage":{"bg":"POLICE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"고마워, 덕분에......","JPN":"ありがとう、おかげで……","ENG":"Th-thank you.","TWN":"謝謝，多虧有妳……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네? 너무 작게 말씀하셔서 잘 안 들려요.","JPN":"はい？　声が小さすぎてよく聞こえません。","ENG":"Sorry? I can't hear you. Can you speak up, please?","TWN":"咦？妳的聲音太小了，我沒聽清楚。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"돼, 됐어! 못 들은 걸로 해!","JPN":"もういい！　聞かなかったことにして！","ENG":"F-forget it! I didn't say anything!","TWN":"隨、隨便啦！沒聽到就沒聽到！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"정말로 못 들었는데......","JPN":"本当に聞こえなかったのに……","ENG":"Come on, I really didn't hear you.","TWN":"我真的沒聽到啊……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그나저나 그 애...... 아니, 그 괴물은 어떻게 됐어?","JPN":"ところであの子……いや、あの怪物はどうなったの？","ENG":"The kid... I mean, that monster. What happened to her?","TWN":"不過，那女孩……不，那怪物怎麼樣了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 여학생이라면 경정님을 구하는 동안 마젤란 예언회 녀석들이 납치해 갔어요.","JPN":"あの女子生徒なら警視様を救出している間、マジェラン預言会のやつらに連れ去られました。","ENG":"The maniacs from Magellan's Prediction Society took her while I was saving you.","TWN":"那個女學生的話，在我救警正大人的時候，被麥哲倫預言會那些傢伙綁走了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 도망치는 것 하나는 정말 재빠른 녀석들이란 말이죠.","JPN":"はは、逃げ足だけは本当に速いやつらですからね。","ENG":"Those bastards are really good at fleeing, hah hah.","TWN":"哈哈，論逃跑，那些傢伙跑得可快了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐? 그럼 어서 가야지! 이러고 있을 때가 아니잖아!","JPN":"何ですって？　なら早く行かないと！\\nこうしてる場合じゃないでしょ！","ENG":"Huh? Then let's go! We don't have time for this!","TWN":"什麼？那還不快走！現在可不是這樣待著的時候！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......으윽!","JPN":"……ううっ！","ENG":"Hngh!","TWN":"……唔！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG"},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 몸으로 어딜 가려고 그래요?","JPN":"そんな体でどこに行くんですか？","ENG":"Where do you think you're going? You need rest.","TWN":"妳這個身體是想去哪裡呀？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그럼? 나더러 여기서 한심하게 누워있으란 얘기야?","JPN":"じゃあ何？　ここでぼうっと横になってろって言うの？","ENG":"Rest? Do you want me to just lie down and relax here like a fool?","TWN":"所以呢？妳是要我沒出息地躺在這裡嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이유미 경정님.","JPN":"カスカベ警視。","ENG":"Listen to me, Major.","TWN":"李悠美警正大人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 갑자기 안 어울리게 심각한 표정으로......","JPN":"な、何？　急に深刻な顔をして……","ENG":"W-what? Why are you looking so serious, all of a sudden?","TWN":"幹、幹嘛？突然擺出這麼不適合妳的嚴肅表情……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우리 4기동에 왜 사람이 없는지 아세요?","JPN":"どうして第4機動隊に人がいないのか、知ってますか？","ENG":"Do you know why we're so undermanned?","TWN":"知道我們第四機動隊為什麼沒有人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥, 그야 겁만 많고 의지는 약한 무능력자들이 카운터범죄자를 두려워하기 때문이지.","JPN":"ふん、そりゃ臆病な上に意志も弱い無能力者たちが\\nカウンター犯罪者を恐れるからでしょう？","ENG":"Hmpf, it's because incompetents are too scared to face off Counter criminals.","TWN":"哼，自然是因為膽小怯懦的無能者害怕制裁者犯罪分子了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하...... 아주 틀린 말은 아니네요.","JPN":"はは……それも間違いではないですね。","ENG":"Hah hah... I guess you're not completely wrong about that.","TWN":"哈哈……這話也不完全是錯的呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그런데, 한때는 이 부서에도 사람이 많았어요.","JPN":"でも、一時期はこの部署も人が多かったんです。","ENG":"But there was a time when we had more people here.","TWN":"不過，這個部門曾經也有很多人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"대 카운터 전담부서가 처음 만들어졌을 땐, 꽤 많은 사람들이 이곳에 지원했거든요.","JPN":"対カウンター専担部署が初めて作られた時は、多くの人がここに志願しました。","ENG":"When the anti-Counter task force was first established, a lot of people actually volunteered.","TWN":"最初創立反制裁者專案部門時，很多人都志願來這裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"병으로 소중한 걸 잃은 사람이 병을 고치기 위해 의사가 되고,","JPN":"病で大切な人を失った人が、病を治すために医師になって、","ENG":"Just like how people become doctors to treat a disease that took their loved ones away...","TWN":"就像因為疾病痛失所愛的人，所以成為治病救人的醫生，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"범죄에 삶을 빼앗긴 사람이 범죄를 막는 경찰이 되는 게 자연스러운 것처럼.","JPN":"犯罪で人生を奪われた人が、犯罪を防ぐ警察になることが自然なことのように。","ENG":"Or how people who lost someone special to crime become police officers to stop criminals.","TWN":"自然而然地，就會有因為犯罪失去幸福生活，所以成為打擊犯罪的警察一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"카운터 악성범죄가 들끓던 시절, 카운터를 증오하던 사람들은 수도 없이 많았거든요.","JPN":"カウンターによる質の悪い犯罪が多かった頃、\\nカウンターを憎む人は数え切れないほどたくさんいました。","ENG":"Back when things were really bad with violent Counter crime, there was no shortage of folks who despised Counters.","TWN":"在制裁者惡性犯罪頻發的時代，憎惡制裁者的人也數不勝數。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"다들 그런 사연이 있다 보니 카운터 범죄를 근절하겠다는 일념으로 열의가 대단했어요.","JPN":"事情のある人の集まりだったから、カウンター犯罪を根絶するという熱意もすごかったんです。","ENG":"So everyone was really eager to put an end to all Counter crimes back then.","TWN":"所以當時有很多人懷著根絕制裁者犯罪的信念，熱情十分高昂。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"꼭 열혈드라마 속 주인공들을 보는 것 같았죠.","JPN":"まるで熱血なドラマの主人公を見ているようでした。","ENG":"It was like watching those invincible heroes from those cop movies.","TWN":"就像熱血電視劇中的主角們一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"然而……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그렇다고 해서 정말로 아무나 주인공이 되는 건 아니더라고요.","JPN":"だからといって、誰でも主人公になれるわけではなかったんです。","ENG":"It turned out nobody's really that invincible.","TWN":"實際上，並不是每個人都能當主角。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"특히 감정에 휩쓸려서 위험을 무릅쓰다가 다치거나 목숨을 잃는 일이 빈번했어요.","JPN":"感情に流されたせいで危険を冒して、\\n怪我したり命を落とすことがたびたびありました。","ENG":"A lot of people let their emotions cloud their judgement and ended up getting hurt... or worse.","TWN":"尤其是很多人因為無法控制個人情感，貿然行事的結果下，受傷或失去性命的案件層出不窮。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"결국 연이은 패착과 성과부진으로......","JPN":"結局、相次ぐ失敗と成績不振で……","ENG":"And with one failure leading to another...","TWN":"最後，因為接二連三的失敗和業績不佳……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"4기동대는 불과 창설 몇 년 만에 지원이 끊겼죠.","JPN":"第4機動隊への支援は、創設されて数年も経たないうちに途絶えました。","ENG":"It didn't take many years for the top brass to cut off all resources to this team.","TWN":"第四機動隊創建不過短短幾年，就不再有志願者了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......난 달라.","JPN":"……私は違う。","ENG":"I'm not like them.","TWN":"……我不一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"물론 경정님이 그 사람들보다 강하다는 건 저도 잘 알아요.","JPN":"もちろん警視様があの人たちより強いのは、私もわかります。","ENG":"Of course, I know you're a lot stronger than any of them.","TWN":"當然，我知道警正大人妳比那些人強。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 다 함께 움직였다면 그런 위험에 처하지 않았을 거란 것도 분명한 사실이에요.","JPN":"それでも警視様が単独行動をしなかったら、そんな危険に陥らなかったことも事実でしょう？","ENG":"But it's also true that we might not have been put at risk like that if we worked together as a team.","TWN":"可是有一點也是毋庸置疑的，如果當時我們能夠團結合作的話，就不會遇到那樣的危險了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님이 어떤 사연을 가지고 이곳에 지원했는지, 저는 아직 몰라요.","JPN":"警視様にどんな過去があって、どんな理由でここに志願したのか、私は知りません。","ENG":"Look, I don't know why you chose to join SWAT 4,","TWN":"警正大人是因為什麼樣的原因，才來這裡支援的，這我還不知道。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 계속 그런 식으로 감정을 앞세워 무리하다간, 다음 번엔 정말 죽을 수도 있어요.","JPN":"だけど、ずっとこんな風に感情に流されて無茶を続けたら、\\n今度こそ本当に死ぬかもしれません。","ENG":"but letting yourself overwhelmed by your emotions can get you killed in the blink of an eye.","TWN":"但是如果您繼續這樣感情用事，那下次妳真的就死定了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......난 다치는 것 따윈 두렵지 않아.","JPN":"……怪我なんか、怖くない。","ENG":"I'm not afraid of getting hurt.","TWN":"……我不怕受傷這種小事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"난 카운터 범죄자 놈들을 심판하기 위해 경찰이 된 거라고!","JPN":"私はカウンター犯罪者を裁くために警察になったんだから！","ENG":"I became a cop so that I could bring those criminal Counters to justice!","TWN":"我是為了審判那些制裁者罪犯，所以才當警察的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그럴 수만 있다면......","JPN":"それさえできるなら……","ENG":"If only I could do it...","TWN":"只要能做到這件事的話……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......그렇게 심판이 하고 싶었으면 차라리 공부를 해서 법관이 되시지 그랬어요?","JPN":"……そんなに裁きたかったら、勉強して裁判官にでもになれば\\nよかったんじゃないですか？","ENG":"If what you wanted was to judge, why didn't you study and become a judge?","TWN":"……妳這麼想審判他們的話，還不如去好好念書，去當法官吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐, 뭐?","JPN":"な、何ですって？","ENG":"W-what?","TWN":"什、什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경찰은 심판하는 사람이 아니라 시민을 지키는 사람이라고요.","JPN":"警察は審判する人じゃなくて、市民を守る人なんです。","ENG":"The police are the protectors of citizens. We don't judge.","TWN":"警察不是審判者，而是市民的守護者。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"다, 당신이 뭘 알아?! 우, 우리 부모님도......","JPN":"あ、あなたに何がわかるの！？　わ、私の両親も……","ENG":"Y-you don't understand! M-my parents...","TWN":"妳、妳又懂什麼？！我、我的父母也……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"부모님도 저런 녀석들에게 돌아가셨다고!!","JPN":"私の両親もあんなやつらに殺されたのよ！！","ENG":"My parents were also killed by jerks like that!","TWN":"我的父母也是因為那種傢伙去世的！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 끝까지 쫓아가서 그 아이에게 복수하려던 거였군요.","JPN":"だから最後まで追いかけて、あの子に復讐しようとしたんですね。","ENG":"So that's why you wanted to take revenge on that kid.","TWN":"所以妳不惜追殺到底，也要把仇報在那孩子身上啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 아이 가족조사를 좀 해봤어요.","JPN":"あの女子生徒の家族関係を調べてみました。","ENG":"I ran a background check on the kid and her family.","TWN":"我調查了一下那個女孩的家庭。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오빠가 태스크포스에서 용병 일을 하고 있더라고요.","JPN":"兄がタスクフォースカンパニーで傭兵の仕事をしているようです。","ENG":"Her brother is a mercenary working in a TASKFORCE company,","TWN":"她的哥哥正在特遣勢力當傭兵。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이면세계 다이브도 자주 하는 모양인데...... 지난 번 작전에서 크게 다쳤다고 하더라고요.","JPN":"裏世界にも頻繁にダイブしているようですが……\\nこの前の作戦で大怪我をしたと聞きました。","ENG":"and a frequent Counterside diver. He was seriously injured during the last operation he was in.","TWN":"似乎也經常躍入異界……但據說在上一次的作戰中受了重傷。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 그게 걱정이 돼서 엘릭서를 구했던 모양이에요.","JPN":"それが心配で、エリクサーを手に入れようとしたようです。","ENG":"That was why the kid wanted to get the Elixir.","TWN":"因為她很擔心哥哥，所以才去找聖水。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"다음 작전에서도 오빠가 살아 돌아올 수 있도록......","JPN":"次の作戦でも兄が生きて帰ってこられるように……","ENG":"She wanted it to make sure her big brother came back home safely.","TWN":"為了讓哥哥能在下一次作戰中活著回來……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그래도 불법은 불법이야.","JPN":"で、でも違法は違法よ。","ENG":"S-still, illegal is illegal.","TWN":"可、可是，違法就是違法。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자의 사정 같은 거, 일일이 다 받아줬다간......","JPN":"犯罪者の事情なんか、いちいち聞いてたら……","ENG":"We can't be lenient every time a criminal has some sorry excuse...","TWN":"如果犯罪者的個人情況，我們都要一個個體諒的話……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그렇지만, 경정님도 좀 전에 엘릭서를 투여 받았는데요?","JPN":"でも、警視様だってさっきエリクサーを投与されたんですよ？","ENG":"Then what if I were to tell you that you were injected with Elixir just now?","TWN":"不過，警正大人不久前也接受了聖水注射喔？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……え？","ENG":"Huh?","TWN":"……什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저희가 경정님을 구해냈을 땐, 이미 피를 너무 많이 흘리셨어요.","JPN":"私たちが警視様を救出した時は、すでに出血量が多すぎました。","ENG":"When I arrived, you had already lost too much blood.","TWN":"我們救援警正大人的時候，妳已經失血過多了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"내부 출혈이라 응급처치도 불가능했죠.","JPN":"内部出血だから、応急処置も不可能だったんです。","ENG":"The bleeding was primarily internal, and there was nothing I could do to stop it.","TWN":"因為是內部出血，也沒辦法做緊急治療。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 어쩔 수 없이, 제가 압류해둔 엘릭서 소량을 경정님에게 투여했어요.","JPN":"それで仕方なく、私が押収していたエリクサーを少量だけ警視様に投与しました。","ENG":"Then I thought of the confiscated Elixir I was carrying and injected you with a small amount of it.","TWN":"所以我只好為警正大人注射了少量我扣押的聖水。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그게 경정님이 지금 살아계신 이유고요.","JPN":"それが今、警視様が生きている理由なんです。","ENG":"That's why you're still alive.","TWN":"這就是為什麼警正大人現在還活著。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런......","JPN":"そんな……","ENG":"That’s...","TWN":"怎麼會……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 부작용은 걱정 마세요.","JPN":"あ、副作用のことなら心配ありません。","ENG":"Ah, don't worry about the aftereffects.","TWN":"啊，不用擔心副作用。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님은 일단 카운터고, 뭣보다 엘릭서에 대한 내성도 낮으시니까요.","JPN":"警視様はカウンターですし、何よりエリクサーに対する耐性も低いですからね。","ENG":"You're a Counter who hasn't developed much tolerance to Elixir's effects.","TWN":"首先，警正大人是制裁者，並且對於聖水的耐性也很高。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그런 걸 걱정하는 게 아니잖아!","JPN":"そ、そんなことを心配してるんじゃないわ！","ENG":"I-I'm not saying I'm worried about aftereffects!","TWN":"我、我不是擔心這個！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼 어쩌시게요? 약물을 멋대로 남용한 저를 잡아넣기라도 하실 건가요?","JPN":"じゃあ、どうします？\\n勝手に薬物を乱用した私を、刑務所にでもぶち込みますか？","ENG":"Then what? Are you going to book me for drug abuse?","TWN":"那是什麼？是因為我隨便亂用藥物，所以想把我抓起來嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아니면 약물을 복용해서 살아남은 경정님 스스로를 죄인취급 하실 건가요?","JPN":"それとも、薬物の力を借りて生き残ったご自分を自ら罪人扱いされますか？","ENG":"Or live the rest of your life in guilt for using Elixir to survive?","TWN":"還是說，警正大人想把服用藥物，存活下來的自己當成罪人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"這……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경찰은 심판을 하는 사람이 아니라 정의를 지키는 사람입니다.","JPN":"警察の仕事は、処罰ではなく正義を守ることです。","ENG":"I'll say this again. The police exist to protect justice, not to bring judgment upon the people.","TWN":"警察不是審判者，而是守護正義的人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지금 경정님이 지켜내야 할 정의가 뭐죠?","JPN":"今の警視様が守るべき正義は何ですか？","ENG":"What's your idea of justice that you think you must uphold?","TWN":"現在警正大人要守護的正義會是什麼呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하지만...... 그 아이는 이미...... 늦어 버렸는걸......","JPN":"でも……あの子はもう……手遅れだから……","ENG":"But... It's too late for her. She's gone too far.","TWN":"可是……那個女孩已經……來不及了……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그거라면 걱정 마세요. 희망이 아주 없는 건 아니니까.","JPN":"それならご心配なく。全く希望がないわけでもありません。","ENG":"Don't worry, Major. She still has hope.","TWN":"這件事不用擔心。不會完全沒有希望。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 아이. 다시 돌아올 수 있다고요.","JPN":"あの子を元に戻せるかもしれないんです。","ENG":"That kid. We can bring her back.","TWN":"那個女孩，她可以重新變回來的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이걸로.","JPN":"これで。","ENG":"With this.","TWN":"用這個。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그게...... 뭐야?","JPN":"それ……何？","ENG":"What's that?","TWN":"這是……什麼？"},"stage":{"bg":"POLICE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"침식생물학 연구소의 그...... 이름이 뭐라더라? 박...... 박정자?","JPN":"侵食生物学研究所の……名前が何だっけ。\\nナツキ……サチコ？","ENG":"This is an Elixir neutralizer developed by the Corruption Biology Research Lab's Doctor... What has her name? Park... Park Jeongja?","TWN":"侵蝕生物學研究所的那個……名字是什麼來著？朴……朴靜子？"},"stage":{"bg":"POLICE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하여간 최고 권위자 한 분이 최근에 개발하신 엘릭서 중화제에요.","JPN":"とにかく、この分野の最高権威者の方が最近開発された、エリクサー中和剤です。","ENG":"Anyway, one of the most prominent figures in the field.","TWN":"總之就是某個最高權威者，她最近開發的聖水中和劑。"},"stage":{"bg":"POLICE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이런 약품을 정식으로 보급하려면 오랜 기간 안정성 시험을 거쳐야 하지만.","JPN":"もともと薬品を正式に普及させるためには、\\n長い時間をかけて安全性をテストしないといけませんが。","ENG":"These types of chemicals normally go through safety tests for extended periods of time,","TWN":"雖然這種藥物要正式普及，需要經過長時間的安全性測試。"},"stage":{"bg":"POLICE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"워낙 실험정신이 투철하신 분이라, 제가 몰래 부탁 드렸더니 흔쾌히 맡겨주셨죠.","JPN":"実験精神に溢れている方なので、私がこっそりお願いしたら快く引き受けてくださったんです。","ENG":"But she's a very adventurous scholar, and she gave me the sample when I asked her discretely.","TWN":"不過那位本來就有徹底的實驗精神，所以我悄悄地拜託她後，她就爽快地交給我了。"},"stage":{"bg":"POLICE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"중화제? 정말로, 그것만 있으면 치료할 수 있는 거야?","JPN":"中和剤？　本当に、それがあれば治療できるの？","ENG":"A neutralizer? Really? Could it really cure her?","TWN":"中和劑？只要有了這個，真的就能治好她嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아뇨, 이건 정확히는 중화제의 베이스에 불과해요.","JPN":"いいえ、はっきり言ってこれは中和剤のベースに過ぎません。","ENG":"Not really. To be precise, this is only the base of a neutralizer.","TWN":"不，正確來講，這個只是中和劑的基礎。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"엘릭서 투여자가 사용했던 것과 일치하는 유형의 엘릭서를 배합해야 그에 대응하는 중화제가 완성된다고 했어요.","JPN":"エリクサー投与者が使用したものと一致するエリクサーを配合しないと、\\n対応する中和剤が完成しないそうです。","ENG":"The Doctor told me that we'd have to combine this with the same type of Elixir used on the subject's body to make it fully effective.","TWN":"只有搭配注射者所使用的相同類型聖水，才能完成對應的中和劑。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 그 학생이 사용했던 건, 시중을 떠도는 일반적인 엘릭서가 아니었어요.","JPN":"でも、あの女子生徒が使ったものは市中に出回っている一般的なエリクサーではありません。","ENG":"But what that student used was no ordinary Elixir you could get in back alleys.","TWN":"但是那個學生使用的並不是市面流通的一般聖水。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아마, 마젤란 예언회라면 그 해답을 가지고 있겠죠.","JPN":"たぶん、マジェラン預言会なら答えを知っているでしょう。","ENG":"The bastards in the Magellan's Prediction Society will have the answer.","TWN":"我想，麥哲倫預言會應該會有這個問題的答案吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"전 지금부터 밖에 계신 블랙타이드 아저씨들과 그 아이를 구하러 갈 거에요.","JPN":"私は今から待機中のブラックタイドのおじさんたちとあの子を救出しに行きますが。","ENG":"So, I'm going to go save the kid with folks from Blade Tide outside.","TWN":"我要和現在在外面的黑潮大叔們，一起去救那個孩子。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님은 어쩌실 거죠?","JPN":"警視様はどうしますか？","ENG":"What are you going to do, Major?","TWN":"警正大人要怎麼做呢？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경위......","JPN":"警部補……","ENG":"Lieutenant...","TWN":"警衛……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내 무기는 어디 있어?","JPN":"私の武器はどこ？","ENG":"Where's my weapon?","TWN":"我的武器在哪裡？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제 차에 고이 모셔뒀죠.","JPN":"私の車に保管してますよ。","ENG":"It's in my car, intact and untouched.","TWN":"在我車上放得好好的呢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"시동 걸어.","JPN":"エンジンかけて。","ENG":"Get the car ready.","TWN":"發動引擎。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"정의를 지키러 가야지.","JPN":"正義を守りに行かなきゃ。","ENG":"It's time to uphold justice.","TWN":"讓我們去守護正義吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};